@theme {
  /* ── Color Tokens ── */
  --color-background: oklch(1 0 0);
  --color-foreground: oklch(0.145 0 0);
  --color-card: oklch(1 0 0);
  --color-card-foreground: oklch(0.145 0 0);
  --color-popover: oklch(1 0 0);
  --color-popover-foreground: oklch(0.145 0 0);
  --color-primary: oklch(0.65 0.29 350);
  --color-primary-foreground: oklch(0.985 0 0);
  --color-secondary: oklch(0.970 0.005 298);
  --color-secondary-foreground: oklch(0.205 0 0);
  --color-muted: oklch(0.930 0.005 298);
  --color-muted-foreground: oklch(0.460 0.010 298);
  --color-accent: oklch(0.930 0.005 298);
  --color-accent-foreground: oklch(0.205 0 0);
  --color-destructive: oklch(0.550 0.180 25);
  --color-border: oklch(0.205 0 0);
  --color-input: oklch(0.205 0 0);
  --color-ring: oklch(0.65 0.29 350);

  /* ── Sidebar Colors (shadcn compat) ── */
  --color-sidebar: oklch(0.985 0 0);
  --color-sidebar-foreground: oklch(0.145 0 0);
  --color-sidebar-primary: oklch(0.65 0.29 350);
  --color-sidebar-primary-foreground: oklch(0.985 0 0);
  --color-sidebar-accent: oklch(0.930 0.005 298);
  --color-sidebar-accent-foreground: oklch(0.205 0 0);
  --color-sidebar-border: oklch(0.205 0 0);
  --color-sidebar-ring: oklch(0.65 0.29 350);

  /* ── Chart Colors ── */
  --color-chart-1: oklch(0.65 0.29 350);
  --color-chart-2: oklch(0.91 0.18 98);
  --color-chart-3: oklch(0.85 0.25 145);
  --color-chart-4: oklch(0.550 0.010 298);
  --color-chart-5: oklch(0.205 0 0);

  /* ── Radius: 0px everywhere (industrial edges) ── */
  --radius: 0px;
  --radius-xs: 0px;
  --radius-sm: 0px;
  --radius-md: 0px;
  --radius-lg: 0px;
  --radius-xl: 0px;
  --radius-2xl: 0px;
  --radius-3xl: 0px;
  --radius-4xl: 0px;

  /* ── Typography (literal font names — NOT var() refs) ── */
  --font-sans: "Electrolize", "Courier New", "SF Mono", ui-monospace, monospace;
  --font-mono: "JetBrains Mono", "Courier New", "SF Mono", ui-monospace, monospace;
  --font-heading: "Electrolize", "Courier New", "SF Mono", ui-monospace, monospace;
  --font-display: "Anton", "Impact", sans-serif;

  /* ── Type Scale: Augmented Fourth (1.414) ── */
  --text-xs: 0.500rem;
  --text-sm: 0.707rem;
  --text-base: 1.000rem;
  --text-lg: 1.414rem;
  --text-xl: 2.000rem;
  --text-2xl: 2.828rem;
  --text-3xl: 4.000rem;
  --text-4xl: 5.657rem;
}

/* ── Runtime font override (next/font uses hashed names) ── */
:root {
  --font-display: var(--font-anton), "Impact", sans-serif;
}

/* ── SignalframeUX Extension Variables ── */
:root {
  --sf-yellow: oklch(0.91 0.18 98);
  --sf-green: oklch(0.85 0.25 145);
  --sf-clock: oklch(0.145 0 0);
  --color-success: oklch(0.85 0.25 145);
  --color-warning: oklch(0.91 0.18 98);
  --sf-grain-opacity: 0.03;
  --sf-inset-shadow: inset 0 1px 2px oklch(0 0 0 / 0.08);
  --sf-deboss-light: 0 1px 0 oklch(1 0 0 / 0.1);
  --sf-deboss-shadow: 0 -1px 0 oklch(0 0 0 / 0.15);

  /* ── Semantic Surface Tokens ── */
  --sf-code-bg: oklch(0.12 0 0);
  --sf-code-text: oklch(0.6 0.28 145);
  --sf-code-keyword: oklch(0.7 0.15 25);
  --sf-dark-surface: oklch(0.2 0 0);
  --sf-darker-surface: oklch(0.1 0 0);
  --sf-darkest-surface: oklch(0.08 0 0);
  --sf-subtle-border: oklch(0.3 0 0);
  --sf-dim-text: oklch(0.5 0 0);
  --sf-muted-text-dark: oklch(0.65 0 0);

  /* ── Motion Tokens ── */
  --duration-instant: 34ms;
  --duration-fast: 100ms;
  --duration-normal: 200ms;
  --duration-slow: 400ms;
  --duration-glacial: 600ms;
  --ease-default: cubic-bezier(0.2, 0, 0, 1);
  --ease-hover: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-spring: linear(0, 0.009, 0.035 2.1%, 0.141, 0.281 6.7%, 0.723 12.9%, 0.938 16.7%, 1.017, 1.077, 1.121, 1.149 24.3%, 1.159, 1.163, 1.161, 1.154 29.9%, 1.085 32.8%, 1.009 36.5%, 0.982 38.5%, 0.961, 0.946 42.4%, 0.938, 0.934 46.4%, 0.936 49.3%, 0.954 53.5%, 1 62.8%, 1.012 68.8%, 1.006 81.5%, 1);

  /* ── VHS Overlay Tokens ── */
  --vhs-crt-opacity: 0.2;
  --vhs-noise-opacity: 0.015;

  /* ── Press Feedback Tokens ── */
  --press-scale: 0.97;
  --press-y: 1px;
  --hover-y: -2px;
  --focus-ring-width: 2px;
  --focus-ring-offset: 2px;
}

/* ── Dark Mode ── */
.dark {
  --color-background: oklch(0.145 0 0);
  --color-foreground: oklch(0.985 0 0);
  --color-card: oklch(0.205 0 0);
  --color-card-foreground: oklch(0.985 0 0);
  --color-popover: oklch(0.205 0 0);
  --color-popover-foreground: oklch(0.985 0 0);
  --color-secondary: oklch(0.269 0 0);
  --color-secondary-foreground: oklch(0.985 0 0);
  --color-muted: oklch(0.269 0 0);
  --color-muted-foreground: oklch(0.730 0 0);
  --color-accent: oklch(0.269 0 0);
  --color-accent-foreground: oklch(0.985 0 0);
  --color-border: oklch(0.400 0 0);
  --color-input: oklch(0.400 0 0);
  --color-sidebar: oklch(0.205 0 0);
  --color-sidebar-foreground: oklch(0.985 0 0);
  --color-sidebar-primary: oklch(0.65 0.29 350);
  --color-sidebar-primary-foreground: oklch(0.985 0 0);
  --color-sidebar-accent: oklch(0.269 0 0);
  --color-sidebar-accent-foreground: oklch(0.985 0 0);
  --color-sidebar-border: oklch(0.400 0 0);
  --color-sidebar-ring: oklch(0.65 0.29 350);
}
